  const user = await getUserOrThrow();
  const { handles, settings, createdBy } = await retrieveCertificateHandles((await context.params).id);
  if (createdBy !== user.authUserId) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 403 });
  }
